import React from 'react';
import { Link } from 'react-router-dom';
import './ListingCard.css';

function ListingCard({ listing }) {
  // Форматирование цены
  const formatPrice = (price) => {
    if (!price) return 'Цена не указана';
    return price.toLocaleString() + ' ₽';
  };

  // Получение типа сделки
  const getDealType = () => {
    if (listing.deal_type === 'rent') return 'Аренда';
    if (listing.deal_type === 'sale') return 'Продажа';
    return '';
  };

  return (
    <div className="listing-card">
      <Link to={`/listing/${listing.listing_id}`}>
        <div className="card-image">
          <img
            src={listing.photos?.[0]?.file_url || '/no-image.jpg'}
            alt={listing.title}
            onError={(e) => {
              e.target.src = '/no-image.jpg';
            }}
          />
          {listing.deal_type && (
            <span className="deal-badge">{getDealType()}</span>
          )}
        </div>

        <div className="card-content">
          <h3 className="card-title">{listing.title || 'Без названия'}</h3>
          <p className="card-price">{formatPrice(listing.price)}</p>
          <p className="card-address">
            📍 {listing.address || 'Адрес не указан'}
          </p>
          <div className="card-details">
            {listing.total_area && (
              <span>📐 {listing.total_area} м²</span>
            )}
            {listing.rooms && (
              <span>🛏 {listing.rooms} комн</span>
            )}
          </div>
          <p className="card-date">
            📅 {listing.publication_date ?
              new Date(listing.publication_date).toLocaleDateString() :
              'Дата не указана'}
          </p>
        </div>
      </Link>
    </div>
  );
}

export default ListingCard;
